import React from 'react';
import PatientList from './Components/PatientList';
import DoctorList from './Components/DoctorList';
import AppointmentList from './Components/AppointmentList';

function App() {
  return (
    <div className="min-h-screen bg-slate-50 p-4 md:p-8">
      {/* Header sa Imong System */}
      <header className="mb-10 text-center">
        <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">
          Hospital Management System
        </h1>
        <p className="text-slate-500 mt-2">Dashboard Overview for Doctors, Patients, and Schedules</p>
      </header>

      <div className="max-w-7xl mx-auto space-y-12">

        {/* Section para sa Doctors */}
        <section>
          <div className="flex items-center justify-between mb-6 border-b pb-2">
            <h2 className="text-2xl font-bold text-slate-800">👨‍⚕️ Our Doctors</h2>
            <span className="text-sm bg-blue-100 text-blue-700 px-3 py-1 rounded-full font-medium">Active Staff</span>
          </div>
          <DoctorList />
        </section>

        {/* Section para sa Patients */}
        <section>
          <div className="flex items-center justify-between mb-6 border-b pb-2">
            <h2 className="text-2xl font-bold text-slate-800">👥 Registered Patients</h2>
            <button className="text-sm text-teal-600 hover:underline font-medium">+ Add New Patient</button>
          </div>
          <PatientList />
        </section>

        {/* Section para sa Appointments */}
        <section>
          <div className="flex items-center justify-between mb-6 border-b pb-2">
            <h2 className="text-2xl font-bold text-slate-800">📅 Appointments Schedule</h2>
          </div>
          <div className="bg-white rounded-2xl shadow-sm p-6">
             <AppointmentList />
          </div>
        </section>

      </div>
    </div>
  );
}

export default App;
